    <div class="cg">
      <div class="cp" *ngFor="let s of sourceOptions" [class.on]="isSourceOn(s)" (click)="toggleSource(s)">{{s}}</div>
    </div>
    <div class="f" style="margin-top:12px"><label>Others</label><input type="text" [value]="form.sourceOther" (input)="patch('sourceOther',$any($event.target).value)"/></div>
  </div>

  <!-- ══ PART F — CHANNEL PARTNER ══ -->
  <div class="part-head"><span class="part-num">F</span><span class="part-title">Channel Partner Details</span></div>
  <div class="fb">
    <div class="f mb">
      <label>Channel Partner Applicable?</label>
      <div class="rg">
        <div class="rp" [class.on]="form.channelPartner.applicable"  (click)="patchCP('applicable',true)">Yes</div>
        <div class="rp" [class.on]="!form.channelPartner.applicable" (click)="patchCP('applicable',false)">No</div>
      </div>
    </div>
    <div class="g3" *ngIf="form.channelPartner.applicable">
      <div class="f"><label>Name</label><input  id="cp-name"  type="text" [class.error]="showErrors && form.channelPartner.applicable && !form.channelPartner.name"  [value]="form.channelPartner.name"     (input)="patchCP('name',$any($event.target).value)"/></div>
      <div class="f"><label>Mobile</label><input id="cp-mobile" type="number" [class.error]="showErrors && form.channelPartner.applicable && !form.channelPartner.mobile" [value]="form.channelPartner.mobile"   (input)="patchCP('mobile',$any($event.target).value)"/></div>
      <div class="f"><label>Email</label><input id="cp-email" type="email" [class.error]="showErrors && form.channelPartner.applicable && !form.channelPartner.email" [value]="form.channelPartner.email"    (input)="patchCP('email',$any($event.target).value)"/></div>
      <div class="f"><label>RERA No.</label><input id="cp-rera"  type="text"  [class.error]="showErrors && form.channelPartner.applicable && !form.channelPartner.rera"[value]="form.channelPartner.rera"   (input)="patchCP('rera',$any($event.target).value)"/></div>
      <div class="f"><label>GST No.</label><input id="cp-gst" type="text"  [class.error]="showErrors && form.channelPartner.applicable && !form.channelPartner.gst" [value]="form.channelPartner.gst"     (input)="patchCP('gst',$any($event.target).value)"/></div>
      <div class="f"><label>Brokerage %</label><input id="cp-brokerage" type="text" [class.error]="showErrors && form.channelPartner.applicable && !form.channelPartner.brokerage" [value]="form.channelPartner.brokerage" (input)="patchCP('brokerage',$any($event.target).value)"/></div>
    </div>
  </div>

  <!-- ══ PART H — BOOKING PAYMENT ══ -->
  <div class="part-head"><span class="part-num">H</span><span class="part-title">Booking Payment Details</span></div>
  <div class="fb">
    <div class="g3">
      <div class="f"><label>Cheque / UTR No.</label><input type="text" [value]="form.payment.chequeNo"    (input)="patchPayment('chequeNo',$any($event.target).value)"/></div>
      <div class="f"><label>Date</label><input type="date" [value]="form.payment.dated"                   (change)="patchPayment('dated',$any($event.target).value)"/></div>
      <div class="f"><label>Amount (Figures)</label><input type="text" [value]="form.payment.amount"      (input)="patchPayment('amount',$any($event.target).value)" placeholder="₹"/></div>
      <div class="f span3"><label>Amount (Words)</label><input type="text" [value]="form.payment.amountWords" (input)="patchPayment('amountWords',$any($event.target).value)"/></div>
      <div class="f span3"><label>Drawn On (Bank)</label><input type="text" [value]="form.payment.drawnOn"    (input)="patchPayment('drawnOn',$any($event.target).value)"/></div>
      <div class="f span3"><label>Cost Sheet Ref.</label><input type="text" [value]="form.payment.costSheetRef" (input)="patchPayment('costSheetRef',$any($event.target).value)"/></div>
    </div>
  </div>

  <!-- ══ PHOTOGRAPHS & SIGNATURES ══ -->
  <div class="part-head"><span class="part-num">📷</span><span class="part-title">Photograph &amp; Signature</span></div>
  <div class="fb">
    <p class="sub-note" style="margin-bottom:18px">
      Upload a passport-size photograph for each applicant. Sign in the box below using finger, stylus, or mouse.
    </p>
    <div class="photo-sig-grid">
      <div class="photo-sig-col" *ngFor="let app of form.applicants; let i = index; trackBy: trackByIndex">
        <app-photo-upload
          [label]="'Applicant ' + (i+1)"
          [sublabel]="i===0 ? '(Primary)' : ''"
          (photoSelected)="onPhotoSelected(i,$event)"
          (photoCleared)="onPhotoCleared(i)">
        </app-photo-upload>
        <app-signature-pad
          [label]="'Signature ' + (i+1)"
          [mandatory]="i===0"
          (signed)="onSigned('applicant'+(i+1),$event)"
          (cleared)="onSignatureCleared('applicant'+(i+1))">
        </app-signature-pad>
      </div>
    </div>
    <div style="margin-top:24px; max-width:280px" *ngIf="form.channelPartner.applicable">
      <p class="sub-note" style="margin-bottom:10px">Channel Partner / Witness Signature</p>
      <app-signature-pad
        label="Channel Partner / Witness"
        [mandatory]="false"
        (signed)="onSigned('channelPartner',$event)"
        (cleared)="onSignatureCleared('channelPartner')">
      </app-signature-pad>
    </div>
  </div>

  <!-- ══ T&C ══ -->
  <div class="part-head"><span class="part-num">T&amp;C</span><span class="part-title">Terms &amp; Conditions</span></div>
  <div class="fb">
    <div class="note">Please read all Terms &amp; Conditions before accepting. Ticking below confirms you have read, understood and agree to all 46 clauses.</div>
    <div class="tnc-row" (click)="toggleTnc()">
      <div class="tnc-box" [class.checked]="form.tncAccepted"><span *ngIf="form.tncAccepted">✓</span></div>
      <div class="tnc-text">I / We have read, understood and agree to be bound by all Terms &amp; Conditions forming part of this Booking Form.</div>
    </div>
  </div>

</div>
